                </span>
              ) : product ? (
                <span className="flex items-center gap-2">
                  <Pencil className="h-4 w-4" />
                  تحديث
                </span>
              ) : (
                <span className="flex items-center gap-2">
                  <Plus className="h-4 w-4" />
                  إضافة
                </span>
              )}
            </Button>
          </div>
        </form>
      </DialogContent>
    </Dialog>
  );
}

