  productId: string,
  inventoryType: 'mobile' | 'mobile_accessory' | 'mobile_spare_part',
  productName: string,
  costPrice: number,
  salePrice: number,
  quantity: number,
  purchaseDate: string,
  supplier: string,
): void {
  if (quantity <= 0) return;

  addBatch({
    productId,
    inventoryType,
    productName,
    costPrice,
    salePrice,
    quantity,
    remainingQty: quantity,
    purchaseDate,
    supplier,
    notes: 'رصيد افتتاحي (إضافة جديدة)',
  });
}

