type LoginLockoutState = {
  attempts: number;
  lockoutEnd: number | null;
};

const LOGIN_LOCKOUT_KEY = 'elahmed_login_lockout_v1';
const EMPTY_LOCKOUT_STATE: LoginLockoutState = { attempts: 0, lockoutEnd: null };

function readLockoutState(): LoginLockoutState {
  const stored = getStorageItem<LoginLockoutState>(LOGIN_LOCKOUT_KEY, EMPTY_LOCKOUT_STATE);
  if (!stored.lockoutEnd || stored.lockoutEnd > Date.now()) {
    return {
      attempts: Math.max(0, stored.attempts || 0),
      lockoutEnd: stored.lockoutEnd ?? null,
    };
  }

  removeStorageItem(LOGIN_LOCKOUT_KEY);
  return EMPTY_LOCKOUT_STATE;
}

const LoginPage = () => {
  const { login } = useAuth();
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const [lockoutState, setLockoutState] = useState<LoginLockoutState>(() => readLockoutState());
  const [lockoutSec, setLockoutSec] = useState(0);
  const [screen, setScreen] = useState<Screen>('login');
  const [fpUsername, setFpUsername] = useState('');
  const [fpCode, setFpCode] = useState('');
  const [fpPass, setFpPass] = useState('');
  const [fpConfirm, setFpConfirm] = useState('');
  const [fpError, setFpError] = useState('');
  const [fpStep, setFpStep] = useState<1 | 2>(1);
  const [forcePass, setForcePass] = useState('');
  const [forceConfirm, setForceConfirm] = useState('');
  const [forceError, setForceError] = useState('');

  const MAX_ATTEMPTS = 5;
  const LOCKOUT_SEC = 30;
  const attempts = lockoutState.attempts;
  const lockoutEnd = lockoutState.lockoutEnd;
  const setAttempts = useCallback((nextAttempts: number) => {
    setLockoutState((current) => ({ ...current, attempts: nextAttempts }));
  }, []);
  const setLockoutEnd = useCallback((nextLockoutEnd: number | null) => {
    setLockoutState((current) => ({ ...current, lockoutEnd: nextLockoutEnd }));
  }, []);

  useEffect(() => {
    if (lockoutState.attempts === 0 && !lockoutState.lockoutEnd) {
      removeStorageItem(LOGIN_LOCKOUT_KEY);
      return;
    }

    setStorageItem(LOGIN_LOCKOUT_KEY, lockoutState);
  }, [lockoutState]);

  const clearLockout = useCallback(() => {
    setLockoutState(EMPTY_LOCKOUT_STATE);
    setLockoutSec(0);
  }, []);

  useEffect(() => {
    if (!lockoutEnd) return;
    const tick = () => {
      const rem = Math.ceil((lockoutEnd - Date.now()) / 1000);
      if (rem <= 0) { clearLockout(); setError(''); }
      else setLockoutSec(rem);
    };
    tick();
    const id = setInterval(tick, 1000);
    return () => clearInterval(id);
  }, [clearLockout, lockoutEnd]);

  const isLocked = !!lockoutEnd && Date.now() < lockoutEnd;

  const handleLogin = useCallback(async (e: React.FormEvent) => {
    e.preventDefault();
    if (isLocked) return;
    setError(''); setLoading(true);
    try {
      const result = await login(username, password);
      if (result.requiresPasswordChange) {
        clearLockout();
        setForcePass('');
        setForceConfirm('');
        setForceError('');
        setPassword('');
        setScreen('forceChange');
        return;
      }
      if (!result.success) {
        const n = attempts + 1;
        setAttempts(n);
        if (n >= MAX_ATTEMPTS) {
          setLockoutEnd(Date.now() + LOCKOUT_SEC * 1000);
          setError(`تم قفل الحساب مؤقتاً. حاول بعد ${LOCKOUT_SEC} ثانية`);
          return;
        }
        setError(result.error || 'بيانات غير صحيحة');
        return;
        if (n >= MAX_ATTEMPTS) { setLockoutEnd(Date.now() + LOCKOUT_SEC * 1000); setError(`تم قفل الحساب مؤقتاً. حاول بعد ${LOCKOUT_SEC} ثانية`); }
        else setError(result.error || 'بيانات غير صحيحة');
      }
      clearLockout();
      setError('');
    } catch (err) {
      const n = attempts + 1;
      setAttempts(n);
      if (n >= MAX_ATTEMPTS) {
        setLockoutEnd(Date.now() + LOCKOUT_SEC * 1000);
        setError('تم قفل الحساب مؤقتاً');
        return;
      }
      setError(err instanceof Error ? err.message : 'بيانات غير صحيحة');
      return;
      if (n >= MAX_ATTEMPTS) { setLockoutEnd(Date.now() + LOCKOUT_SEC * 1000); setError(`تم قفل الحساب مؤقتاً`); }
      else setError(err instanceof Error ? err.message : 'بيانات غير صحيحة');
    } finally { setLoading(false); }
  }, [LOCKOUT_SEC, attempts, clearLockout, isLocked, login, password, username]);

  const handleFpStep1 = (e: React.FormEvent) => {
    e.preventDefault(); setFpError('');
    if (!findUserByUsername(fpUsername)) { setFpError('اسم المستخدم غير موجود'); return; }
    setFpStep(2);
  };
  const handleFpStep2 = async (e: React.FormEvent) => {
    e.preventDefault(); setFpError('');
    if (!verifyRecoveryCode(fpCode)) { setFpError('كود الاسترداد غير صحيح. تواصل مع صاحب النظام'); return; }
    if (fpPass.length < 4) { setFpError('كلمة المرور 4 أحرف على الأقل'); return; }
    if (fpPass !== fpConfirm) { setFpError('كلمتا المرور غير متطابقتين'); return; }
    try {
      const changed = await changePassword(fpUsername, fpPass);
      if (!changed) { setFpError('حدث خطأ أثناء التغيير'); return; }
      setScreen('done');
    } catch {
      setFpError('حدث خطأ أثناء التغيير');
    }
  };
  const handleForcedPasswordChange = async (e: React.FormEvent) => {
    e.preventDefault();
    setForceError('');

    if (forcePass.length < 4) {
      setForceError('كلمة المرور يجب أن تكون 4 أحرف على الأقل');
      return;
    }

    if (forcePass !== forceConfirm) {
      setForceError('كلمتا المرور غير متطابقتين');
      return;
    }

    setLoading(true);
    try {
      const changed = await changePassword(username, forcePass);
      if (!changed) {
        setForceError('تعذر تحديث كلمة المرور');
        return;
      }
      setScreen('done');
    } catch {
      setForceError('حدث خطأ أثناء تحديث كلمة المرور');
    } finally {
      setLoading(false);
    }
  };

  const goLogin = () => {
    setScreen('login');
    setUsername('');
    setPassword('');
    setError('');
    setFpStep(1);
    setFpError('');
    setFpUsername('');
    setFpCode('');
    setFpPass('');
    setFpConfirm('');
    setForcePass('');
    setForceConfirm('');
    setForceError('');
  };

  const fieldClass = "h-12 w-full rounded-xl border border-white/10 bg-white/5 px-4 text-sm text-white placeholder:text-white/30 focus:outline-none focus:ring-2 focus:ring-primary/40 focus:border-primary/50 transition-all duration-300 backdrop-blur-sm";

  /* ── DONE ── */
  if (screen === 'done') return (
    <GlassCard>
      <div className="p-8 text-center space-y-5">
        <div className="flex justify-center">
          <div className="flex h-16 w-16 items-center justify-center rounded-full bg-emerald-500/20 border border-emerald-500/30">
            <CheckCircle className="h-8 w-8 text-emerald-400" />
          </div>
        </div>
        <h2 className="text-xl font-bold text-white">تم تغيير كلمة المرور</h2>
        <p className="text-sm text-white/50">يمكنك الآن تسجيل الدخول بكلمة المرور الجديدة</p>
        <button onClick={goLogin} className="w-full h-12 rounded-xl bg-gradient-to-l from-primary to-primary/80 font-bold text-white hover:opacity-90 transition-all shadow-lg shadow-primary/25">
          العودة لتسجيل الدخول
        </button>
      </div>
    </GlassCard>
  );

  /* ── FORGOT ── */
  if (screen === 'forceChange') return (
    <GlassCard>
      <div className="p-6 space-y-5">
        <div className="text-center space-y-3 pt-2">
          <div className="flex justify-center">
            <div className="relative flex h-16 w-16 items-center justify-center rounded-2xl bg-gradient-to-br from-primary to-primary/70 shadow-lg shadow-primary/30">
              <div className="absolute inset-0 rounded-2xl bg-primary/40 blur-lg opacity-60 animate-pulse" />
              <ShieldCheck className="relative h-8 w-8 text-white" />
            </div>
          </div>
          <h2 className="text-2xl font-bold text-white">تغيير كلمة المرور مطلوب</h2>
          <p className="text-sm text-white/50">الحساب الافتراضي لا يدخل للنظام قبل تعيين كلمة مرور جديدة.</p>
        </div>

        <div className="rounded-xl bg-amber-500/10 border border-amber-500/30 p-3 text-center">
          <p className="text-xs text-amber-300/80">المستخدم الحالي: <span className="font-mono font-bold text-amber-300">{username}</span></p>
        </div>

        <form onSubmit={handleForcedPasswordChange} className="space-y-4">
          <div className="space-y-2">
            <label className="flex items-center gap-2 text-sm text-white/70 font-medium"><Lock className="h-4 w-4 text-primary" /> كلمة المرور الجديدة</label>
            <PasswordField value={forcePass} onChange={setForcePass} minLength={4} autoFocus placeholder="أدخل كلمة مرور جديدة" className={fieldClass} />
          </div>
          <div className="space-y-2">
            <label className="flex items-center gap-2 text-sm text-white/70 font-medium"><Lock className="h-4 w-4 text-primary" /> تأكيد كلمة المرور</label>
            <PasswordField value={forceConfirm} onChange={setForceConfirm} placeholder="أعد كتابة كلمة المرور" className={fieldClass} />
          </div>
          {forceError && <Alert variant="destructive" className="bg-destructive/10 border-destructive/30"><AlertTriangle className="h-4 w-4" /><AlertDescription>{forceError}</AlertDescription></Alert>}
          <button type="submit" disabled={loading} className="w-full h-11 rounded-xl bg-gradient-to-l from-primary to-primary/80 font-bold text-white hover:opacity-90 transition-all shadow-lg shadow-primary/20 disabled:opacity-50 flex items-center justify-center gap-2">
            {loading ? <><Loader2 className="h-5 w-5 animate-spin" /> جارٍ الحفظ...</> : 'حفظ كلمة المرور'}
          </button>
          <button type="button" onClick={goLogin} className="w-full h-10 rounded-xl text-sm text-white/50 hover:text-white hover:bg-white/5 transition-all">
            العودة
          </button>
        </form>
      </div>
    </GlassCard>
  );

  if (screen === 'forgot') return (
    <GlassCard>
      <div className="p-6 space-y-5">
        <div className="text-center space-y-3 pt-2">
          <div className="flex justify-center">
            <div className="relative flex h-16 w-16 items-center justify-center rounded-2xl bg-gradient-to-br from-primary to-primary/70 shadow-lg shadow-primary/30">
              <div className="absolute inset-0 rounded-2xl bg-primary/40 blur-lg opacity-60 animate-pulse" />
              <KeyRound className="relative h-8 w-8 text-white" />
            </div>
          </div>
          <h2 className="text-2xl font-bold text-white">استرداد كلمة المرور</h2>
          <p className="text-sm text-white/50">{fpStep === 1 ? 'أدخل اسم المستخدم للمتابعة' : 'تواصل مع صاحب النظام للحصول على كود الاسترداد'}</p>
        </div>
        <div className="flex items-center justify-center gap-2">
          {[1, 2].map(n => (<React.Fragment key={n}>
            {n > 1 && <div className={`h-px w-12 transition-all ${fpStep >= n ? 'bg-primary' : 'bg-white/20'}`} />}
            <div className={`flex h-7 w-7 items-center justify-center rounded-full text-xs font-bold transition-all ${fpStep >= n ? 'bg-primary text-white' : 'bg-white/10 text-white/40'}`}>{n}</div>
          </React.Fragment>))}
        </div>
        {fpStep === 1 ? (
          <form onSubmit={handleFpStep1} className="space-y-4">
            <div className="space-y-2">
              <label className="flex items-center gap-2 text-sm text-white/70 font-medium"><User className="h-4 w-4 text-primary" /> اسم المستخدم</label>
              <input value={fpUsername} onChange={e => setFpUsername(e.target.value)} required autoFocus placeholder="أدخل اسم المستخدم" className={fieldClass} />
            </div>
            {fpError && <Alert variant="destructive" className="bg-destructive/10 border-destructive/30"><AlertTriangle className="h-4 w-4" /><AlertDescription>{fpError}</AlertDescription></Alert>}
            <button type="submit" className="w-full h-11 rounded-xl bg-gradient-to-l from-primary to-primary/80 font-bold text-white hover:opacity-90 transition-all shadow-lg shadow-primary/20">متابعة</button>
            <button type="button" onClick={goLogin} className="w-full h-10 rounded-xl text-sm text-white/50 hover:text-white hover:bg-white/5 transition-all flex items-center justify-center gap-2"><RotateCcw className="h-4 w-4" /> العودة</button>
          </form>
        ) : (
          <form onSubmit={handleFpStep2} className="space-y-4">
            <div className="rounded-xl bg-amber-500/10 border border-amber-500/30 p-3 text-center">
              <p className="text-xs text-amber-300/80">تواصل مع صاحب النظام وأطلب منه <span className="font-bold">كود الاسترداد</span></p>
              <p className="text-xs text-amber-300/50 mt-1">للمستخدم: <span className="font-mono font-bold text-amber-300/80">{fpUsername}</span></p>
            </div>
            <div className="space-y-2"><label className="flex items-center gap-2 text-sm text-white/70 font-medium"><ShieldCheck className="h-4 w-4 text-primary" /> كود الاسترداد</label><input value={fpCode} onChange={e => setFpCode(e.target.value)} required autoFocus placeholder="أدخل الكود" className={`${fieldClass} text-center font-mono tracking-widest text-lg`} /></div>
            <div className="space-y-2"><label className="flex items-center gap-2 text-sm text-white/70 font-medium"><Lock className="h-4 w-4 text-primary" /> كلمة المرور الجديدة</label><PasswordField value={fpPass} onChange={setFpPass} minLength={4} placeholder="4 أحرف على الأقل" className={fieldClass} /></div>
            <div className="space-y-2"><label className="flex items-center gap-2 text-sm text-white/70 font-medium"><Lock className="h-4 w-4 text-primary" /> تأكيد كلمة المرور</label><PasswordField value={fpConfirm} onChange={setFpConfirm} placeholder="أعد كتابة كلمة المرور" className={fieldClass} /></div>
            {fpError && <Alert variant="destructive" className="bg-destructive/10 border-destructive/30"><AlertTriangle className="h-4 w-4" /><AlertDescription>{fpError}</AlertDescription></Alert>}
            <button type="submit" className="w-full h-11 rounded-xl bg-gradient-to-l from-primary to-primary/80 font-bold text-white hover:opacity-90 transition-all shadow-lg shadow-primary/20">تغيير كلمة المرور</button>
            <button type="button" onClick={() => { setFpStep(1); setFpError(''); }} className="w-full h-10 rounded-xl text-sm text-white/50 hover:text-white hover:bg-white/5 transition-all">رجوع</button>
          </form>
        )}
      </div>
    </GlassCard>
  );

  /* ── MAIN LOGIN ── */
  return (
    <GlassCard>
      <div className="p-6" data-testid="login-page">
        {/* Logo & Title */}
        <div className="flex flex-col items-center gap-1 pt-2 pb-5 text-center">
          <div className="relative mb-3">
            <div className="absolute inset-0 rounded-2xl bg-gradient-to-br from-primary to-secondary blur-xl opacity-40 animate-pulse" />
            <div className="absolute -inset-2 rounded-3xl border border-primary/20 animate-pulse-ring" />
            <div className="relative flex h-24 w-24 items-center justify-center rounded-2xl bg-gradient-to-br from-primary/90 via-indigo-500 to-violet-600 shadow-2xl shadow-primary/40 border border-white/10">
              <span className="text-5xl font-black text-white" style={{ fontFamily: 'Georgia, serif' }}>E</span>
            </div>
          </div>
          <h1 className="text-3xl font-bold text-white animate-slide-up flex items-center gap-2">
            الأحمد سيستم <Sparkles className="h-5 w-5 text-primary animate-pulse" />
          </h1>
          <p className="text-white/50 text-base animate-slide-up">حلول إدارة الموبايلات والاكسسوارات</p>
        </div>

        <form onSubmit={handleLogin} className="space-y-5">
          {/* Username */}
          <div className="space-y-2">
            <label htmlFor="username" className="flex items-center gap-2 text-sm font-medium text-white/70">
              <User className="h-4 w-4 text-primary" /> اسم المستخدم
            </label>
            <div className="relative">
              <input id="username" data-testid="login-username" value={username} onChange={e => setUsername(e.target.value)}
                placeholder="أدخل اسم المستخدم" required autoFocus autoComplete="username"
                disabled={loading || isLocked}
                className="h-12 w-full rounded-xl border border-white/10 bg-white/5 pr-12 pl-4 text-sm text-white placeholder:text-white/30 focus:outline-none focus:ring-2 focus:ring-primary/40 focus:border-primary/50 transition-all duration-300 disabled:opacity-50 backdrop-blur-sm" />
              <div className="absolute right-4 top-1/2 -translate-y-1/2 flex h-7 w-7 items-center justify-center rounded-lg bg-primary/10">
                <User className="h-4 w-4 text-primary" />
              </div>
            </div>
          </div>

          {/* Password */}
          <div className="space-y-2">
            <label htmlFor="password" className="flex items-center gap-2 text-sm font-medium text-white/70">
              <KeyRound className="h-4 w-4 text-primary" /> كلمة المرور
            </label>
            <PasswordField
              id="password"
              dataTestId="login-password"
              value={password}
              onChange={setPassword}
              disabled={loading || isLocked}
            />
          </div>

          {/* Error */}
          {error && !isLocked && (
            <Alert variant="destructive" className="bg-destructive/10 border-destructive/30 animate-slide-down backdrop-blur-sm">
              <AlertTriangle className="h-4 w-4" />
              <AlertDescription className="text-destructive">{error}</AlertDescription>
            </Alert>
          )}

          {/* Lockout */}
          {isLocked && (
            <div className="flex items-center justify-center gap-3 rounded-xl bg-amber-500/10 border border-amber-500/20 px-4 py-4 animate-slide-down backdrop-blur-sm">
              <Lock className="h-5 w-5 text-amber-400" />
              <div className="text-center">
                <span className="text-sm text-amber-400/80 block">محظور مؤقتاً</span>
                <span className="text-2xl font-bold text-amber-400">{lockoutSec} ثانية</span>
              </div>
            </div>
          )}

          {/* Attempts */}
          {!isLocked && attempts > 0 && attempts < MAX_ATTEMPTS && (
            <div className="flex items-center justify-center gap-2 rounded-xl bg-amber-500/5 border border-amber-500/10 px-4 py-2 animate-fade-in">
              <ShieldCheck className="h-4 w-4 text-amber-500/60" />
              <p className="text-sm text-amber-500/80"><span className="font-bold">{MAX_ATTEMPTS - attempts}</span> محاولات متبقية</p>
            </div>
          )}

          {/* Submit */}
          <button type="submit" data-testid="login-submit" disabled={loading || isLocked}
            className="w-full h-12 rounded-xl bg-gradient-to-l from-primary to-primary/80 font-bold text-base text-white hover:opacity-90 transition-all duration-300 shadow-lg shadow-primary/25 disabled:opacity-50 flex items-center justify-center gap-2 btn-ripple">
            {loading
              ? <><Loader2 className="h-5 w-5 animate-spin" /> جاري تسجيل الدخول...</>
              : isLocked
                ? <><Lock className="h-5 w-5" /> محظور مؤقتاً</>
                : 'تسجيل الدخول'}
          </button>

          {/* Forgot */}
          <div className="text-center">
            <button type="button" onClick={() => { setScreen('forgot'); setFpUsername(username); }}
              className="text-sm text-primary/70 hover:text-primary underline underline-offset-4 transition-colors">
              نسيت كلمة المرور؟
            </button>
          </div>
        </form>
      </div>
    </GlassCard>
  );
};

