              )}
            </div>
          )}
        </div>

        {/* ── Right Panel: Cart / Payment ── */}
        <CheckoutSidebar
          cart={cart}
          onUpdateQty={updateQtyByDelta}
          onRemove={removeFromCart}
          onLineDiscount={updateLineDiscount}
          onClearCart={clearCart}
          onHoldInvoice={holdInvoice}
