// ── Helpers ──────────────────────────────────────────────────
const fmt = (n: number) => n.toLocaleString('ar-EG', { maximumFractionDigits: 0 });
const fmtK = (n: number) => n >= 1000 ? `${(n / 1000).toFixed(1)}ك` : fmt(n);
const MONTHS_AR = ['يناير', 'فبراير', 'مارس', 'أبريل', 'مايو', 'يونيو', 'يوليو', 'أغسطس', 'سبتمبر', 'أكتوبر', 'نوفمبر', 'ديسمبر'];
const DAYS_AR = ['أحد', 'اثنين', 'ثلاثاء', 'أربعاء', 'خميس', 'جمعة', 'سبت'];

const CHART_COLORS = ['#6366f1', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#06b6d4', '#f97316'];

// ── Types ─────────────────────────────────────────────────────
type DateRange = 'today' | 'week' | 'month' | '3months' | '6months' | 'year' | 'all';

const DATE_LABELS: Record<DateRange, string> = {
    today: 'اليوم', week: 'هذا الأسبوع', month: 'هذا الشهر',
    '3months': 'آخر 3 أشهر', '6months': 'آخر 6 أشهر', year: 'هذا العام', all: 'الكل',
};

function getDateRange(range: DateRange): { from: string; to: string } {
    const now = new Date();
    const to = now.toISOString().slice(0, 10);
    const from = new Date(now);
    if (range === 'today') { /* same */ }
    else if (range === 'week') from.setDate(from.getDate() - 7);
    else if (range === 'month') from.setMonth(from.getMonth() - 1);
    else if (range === '3months') from.setMonth(from.getMonth() - 3);
    else if (range === '6months') from.setMonth(from.getMonth() - 6);
    else if (range === 'year') from.setFullYear(from.getFullYear() - 1);
    else from.setFullYear(2000);
    return { from: from.toISOString().slice(0, 10), to };
}

function inRange(dateStr: string | undefined, from: string, to: string) {
    if (!dateStr) return false;
    const d = dateStr.slice(0, 10);
    return d >= from && d <= to;
}

// ── KPI Card ─────────────────────────────────────────────────
function KPICard({ label, value, sub, icon: Icon, color, trend }:
    { label: string; value: string; sub?: string; icon: React.ElementType; color: string; trend?: 'up' | 'down' | null }) {
    return (
        <div className={`rounded-2xl border bg-card p-5 shadow-[0_2px_8px_rgba(0,0,0,0.05)] border-border/50 relative overflow-hidden`}>
            <div className={`absolute inset-x-0 top-0 h-1 ${color}`} />
            <div className="flex items-start justify-between gap-3">
                <div className="min-w-0 flex-1">
                    <p className="text-xs font-semibold text-muted-foreground">{label}</p>
                    <p className="text-xl font-black text-foreground tabular-nums mt-0.5 leading-tight">{value}</p>
                    {sub && <p className="text-[10px] text-muted-foreground mt-0.5">{sub}</p>}
                </div>
                <div className={`h-10 w-10 rounded-xl flex items-center justify-center shrink-0 ${color.replace('bg-', 'bg-').replace('500', '500/15')}`}>
                    <Icon className={`h-5 w-5 ${color.replace('bg-', 'text-')}`} />
                </div>
            </div>
            {trend && (
                <div className={`mt-2 flex items-center gap-1 text-xs font-bold ${trend === 'up' ? 'text-emerald-500' : 'text-red-500'}`}>
                    {trend === 'up' ? <TrendingUp className="h-3 w-3" /> : <TrendingDown className="h-3 w-3" />}
                    <span>{trend === 'up' ? 'ارتفاع' : 'انخفاض'}</span>
                </div>
            )}
        </div>
    );
}

// ── Section Title ─────────────────────────────────────────────
function SecTitle({ title, sub }: { title: string; sub?: string }) {
    return (
        <div className="mb-3">
            <h3 className="text-base font-bold text-foreground">{title}</h3>
            {sub && <p className="text-xs text-muted-foreground">{sub}</p>}
        </div>
    );
}

// ── Card wrapper ──────────────────────────────────────────────
function Card({ children, className }: { children: React.ReactNode; className?: string }) {
    return (
        <div className={cn('rounded-2xl border border-border/50 bg-card p-5 shadow-[0_2px_8px_rgba(0,0,0,0.04)]', className)}>
            {children}
        </div>
    );
}

// ── Custom Tooltip ────────────────────────────────────────────
function ChartTooltip({ active, payload, label }: any) {
    if (!active || !payload?.length) return null;
    return (
        <div className="rounded-xl border border-border bg-card shadow-xl px-3 py-2 text-xs">
            <p className="font-bold text-foreground mb-1">{label}</p>
            {payload.map((p: any) => (
                <p key={p.dataKey} style={{ color: p.color }} className="font-semibold">
                    {p.name}: {fmt(p.value)} ج.م
                </p>
            ))}
        </div>
    );
}

// ═══════════════════════════════════════════════════════════════
// MAIN REPORTS PAGE
// ═══════════════════════════════════════════════════════════════
export default function ReportsPage() {
    const [dateRange, setDateRange] = useState<DateRange>('month');
    const [activeTab, setActiveTab] = useState('overview');
    const [refreshKey, setRefreshKey] = useState(0);

    useEffect(() => {
        const handleStorage = (e: StorageEvent | CustomEvent) => {
            const key = 'key' in e ? e.key : (e as CustomEvent).detail?.key;
            if (key && (key.startsWith('gx_') || key.startsWith('elahmed_'))) {
                setRefreshKey((current) => current + 1);
            }
        };

        window.addEventListener('storage', handleStorage as EventListener);
        window.addEventListener('local-storage', handleStorage as EventListener);
        return () => {
            window.removeEventListener('storage', handleStorage as EventListener);
            window.removeEventListener('local-storage', handleStorage as EventListener);
        };
    }, []);

    // ── Raw Data ───────────────────────────────────────────────
    const allSales = useMemo(() => getAllSales(), [refreshKey]);
    const mobiles = useMemo(() => getMobiles(), [refreshKey]);
    const mobileAcc = useMemo(() => getMobileAccessories(), [refreshKey]);
    const computers = useMemo(() => getComputers(), [refreshKey]);
    const computerAcc = useMemo(() => getComputerAccessories(), [refreshKey]);
    const devices = useMemo(() => getDevices(), [refreshKey]);
    const deviceAcc = useMemo(() => getDeviceAccessories(), [refreshKey]);
    const cars = useMemo(() => getCars(), [refreshKey]);
    const maintenance = useMemo(() => getMaintenanceOrders(), [refreshKey]);
    const contracts = useMemo(() => getContracts(), [refreshKey]);
    const expenses = useMemo(() => getExpenses(), [refreshKey]);
    const damagedItems = useMemo(() => getDamagedItems(), [refreshKey]);
    const otherRevenues = useMemo(() => getOtherRevenues(), [refreshKey]);
    // #18 FIX: New module data
    const suppliers = useMemo(() => getSuppliers(), [refreshKey]);
    const supplierTxns = useMemo(() => getSupplierTransactions(), [refreshKey]);
    
    // #18 FIX Async wallets data
    const [wallets, setWallets] = useState<WalletType[]>([]);
    const [walletTxns, setWalletTxns] = useState<WalletTransaction[]>([]);
    const [walletTotalBalance, setWalletTotalBalance] = useState(0);

    useEffect(() => {
        let cancelled = false;

        const loadWalletsData = async () => {
            try {
                const [nextWallets, nextWalletTxns, nextWalletBalance] = await Promise.all([
                    getWallets(),
                    getWalletTransactions(),
                    getTotalBalance(),
                ]);

                if (cancelled) return;
                setWallets(nextWallets);
                setWalletTxns(nextWalletTxns);
                setWalletTotalBalance(nextWalletBalance);
            } catch (error) {
                console.error('Failed to load wallet reports data', error);
            }
        };

        loadWalletsData();

        return () => {
            cancelled = true;
        };
    }, [refreshKey]);
    const employees = useMemo(() => getEmployees(), [refreshKey]);

    // ── Date filtering ─────────────────────────────────────────
    const { from, to } = useMemo(() => getDateRange(dateRange), [dateRange]);
    const sales = useMemo(
        () => allSales.filter(s => !s.voidedAt && inRange(s.date, from, to)),
        [allSales, from, to]
    );
    const filteredMaint = useMemo(
        () => maintenance.filter(m => inRange(m.createdAt, from, to)),
        [maintenance, from, to]
    );
    const filteredExpenses = useMemo(
        () => expenses.filter(e => inRange(e.date, from, to)),
        [expenses, from, to]
    );
    const filteredContracts = useMemo(
        () => contracts.filter(c => inRange(c.createdAt || (c as any).date, from, to)),
        [contracts, from, to]
    );

    // ── Core KPIs ─────────────────────────────────────────────
    const activeSales = useMemo(() => filterActiveSales(sales), [sales]);
    const salesSummary = useMemo(() => summarizeSales(activeSales), [activeSales]);
    const totalExpenses = useMemo(() => filteredExpenses.reduce((s, e) => s + e.amount, 0), [filteredExpenses]);
    const maintRevenue = useMemo(() => filteredMaint.reduce((s, m) => s + m.totalSale, 0), [filteredMaint]);
    const maintProfit = useMemo(() => filteredMaint.reduce((s, m) => s + m.netProfit, 0), [filteredMaint]);
    const totalOtherRev = useMemo(() => otherRevenues.filter(o => inRange(o.date, from, to)).reduce((s, o) => s + o.amount, 0), [otherRevenues, from, to]);
    const totalDamaged = useMemo(() => damagedItems.filter(d => inRange(d.date, from, to)).reduce((s, d) => s + d.totalLoss, 0), [damagedItems, from, to]);
    const netProfit = salesSummary.totalProfit + maintProfit + totalOtherRev - totalExpenses - totalDamaged;
    const profitMargin = salesSummary.profitMarginPercent;
    const avgInvoice = salesSummary.avgInvoice;
    const totalRevenue = salesSummary.totalRevenue;
    const totalProfit = salesSummary.totalProfit;

    // ── Inventory Values ──────────────────────────────────────
    const mobileInvValue = useMemo(() => mobiles.reduce((s, m) => s + (getWeightedAvgCost(m.id) || m.newCostPrice) * (m.quantity || 1), 0), [mobiles]);
    const computerInvValue = useMemo(() => computers.reduce((s, c) => s + (getWeightedAvgCost(c.id) || c.newCostPrice) * (c.quantity || 1), 0), [computers]);
    const deviceInvValue = useMemo(() => devices.reduce((s, d) => s + (getWeightedAvgCost(d.id) || d.newCostPrice) * (d.quantity || 1), 0), [devices]);
    const carsInvValue = useMemo(() => cars.reduce((s, c) => s + c.purchasePrice, 0), [cars]);
    const totalInvValue = mobileInvValue + computerInvValue + deviceInvValue + carsInvValue;
    const salesByDay = useMemo(() => {
        const grouped = new Map<string, typeof sales>();
        sales.forEach((sale) => {
            const key = sale.date?.slice(0, 10);
            if (!key) return;

            const current = grouped.get(key);
            if (current) current.push(sale);
            else grouped.set(key, [sale]);
        });
        return grouped;
    }, [sales]);
    const maintenanceByDay = useMemo(() => {
        const grouped = new Map<string, typeof filteredMaint>();
        filteredMaint.forEach((order) => {
            const key = order.createdAt?.slice(0, 10);
            if (!key) return;

            const current = grouped.get(key);
            if (current) current.push(order);
            else grouped.set(key, [order]);
        });
        return grouped;
    }, [filteredMaint]);
    const salesByMonth = useMemo(() => {
        const grouped = new Map<string, typeof allSales>();
        allSales.forEach((sale) => {
            if (sale.voidedAt) return;

            const key = sale.date?.slice(0, 7);
            if (!key) return;

            const current = grouped.get(key);
            if (current) current.push(sale);
            else grouped.set(key, [sale]);
        });
        return grouped;
    }, [allSales]);
    const maintenanceByMonth = useMemo(() => {
        const grouped = new Map<string, typeof maintenance>();
        maintenance.forEach((order) => {
            const key = order.createdAt?.slice(0, 7);
            if (!key) return;

            const current = grouped.get(key);
            if (current) current.push(order);
            else grouped.set(key, [order]);
        });
        return grouped;
    }, [maintenance]);
    const expensesByMonth = useMemo(() => {
        const grouped = new Map<string, typeof expenses>();
        expenses.forEach((expense) => {
            const key = expense.date?.slice(0, 7);
            if (!key) return;

            const current = grouped.get(key);
            if (current) current.push(expense);
            else grouped.set(key, [expense]);
        });
        return grouped;
    }, [expenses]);
    const todaySalesCount = useMemo(() => {
        const today = new Date().toISOString().slice(0, 10);
        return allSales.filter((sale) => !sale.voidedAt && sale.date?.startsWith(today)).length;
    }, [allSales]);
    const owedToSuppliers = useMemo(() => getTotalOwedToSuppliers(), [suppliers]);
    const sortedWallets = useMemo(() => [...wallets].sort((a, b) => b.balance - a.balance), [wallets]);
    const recentWalletTxns = useMemo(
        () => [...walletTxns].sort((a, b) => b.date.localeCompare(a.date)).slice(0, 8),
        [walletTxns]
    );
    const walletDepositCount = useMemo(() => walletTxns.filter((txn) => txn.type === 'deposit').length, [walletTxns]);
    const walletWithdrawalCount = useMemo(() => walletTxns.filter((txn) => txn.type === 'withdrawal').length, [walletTxns]);
    const activeEmployeesCount = useMemo(() => employees.filter((employee) => employee.isActive).length, [employees]);
    const inactiveEmployeesCount = useMemo(() => employees.filter((employee) => !employee.isActive).length, [employees]);
    const totalSalary = useMemo(() => employees.reduce((sum, employee) => sum + (employee.baseSalary || 0), 0), [employees]);

    // ── Daily Sales for chart ─────────────────────────────────
    const dailyData = useMemo(() => {
        const days = dateRange === 'today' ? 1 : dateRange === 'week' ? 7 : dateRange === 'month' ? 30 : 90;
        return Array.from({ length: Math.min(days, 30) }, (_, i) => {
            const d = new Date(); d.setDate(d.getDate() - (Math.min(days, 30) - 1 - i));
