        };
    }), [expensesByMonth, maintenanceByMonth, salesByMonth]);

    // ── Revenue distribution pie ──────────────────────────────
    const revenuePie = useMemo(() => {
        const data = [
            { name: 'موبيلات', value: 0 },
            { name: 'كمبيوترات', value: 0 },
            { name: 'أجهزة', value: 0 },
            { name: 'سيارات', value: 0 },
            { name: 'صيانة', value: maintRevenue },
