    const [balance, setBalance] = useState('0');
    const [loading, setLoading] = useState(false);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!name.trim()) return;
        setLoading(true);
        try {
            await addWallet({ name, icon, color, balance: parseFloat(balance) || 0, isDefault: false });
            onDone();
            onClose();
        } catch (err) {
            console.error(err);
        } finally {
            setLoading(false);
        }
